// Two realistic bulk-delete requests. Same gate, same ability, two
// different real-world shapes -- a small targeted cleanup of soft-deletable
// rows, and a large untargeted wipe of a live table. The point of this demo
// is that Reeflex routes on the DECLARED RISK AXES (reversibility / blast
// radius / externality), not on the row count alone -- count is informational
// (magnitude.count) and feeds the separate fragmentation-budget check (see
// demo 2), it is not itself what R2 keys on.
return [
  {
    json: {
      table: 'stale_carts',
      count: 3,
      reversibility: 'recoverable',
      blastRadius: 'single',
      environment: 'production',
      externality: 'internal',
      story: 'small, soft-deletable, targeted cleanup -> expect ALLOWED'
    }
  },
  {
    json: {
      table: 'customers',
      count: 50,
      reversibility: 'irreversible',
      blastRadius: 'broad',
      environment: 'production',
      externality: 'internal',
      story: 'large hard-delete of a live production table -> expect HELD FOR APPROVAL'
    }
  }
];
